      code: `// Better console methods\nconst users = [\n    { name: "Jenna", role: "Dev" },\n    { name: "Alex", role: "Design" }\n];\nconsole.table(users);\n\nconsole.group("User Data");\nconsole.log("Count:", users.length);\nconsole.log("First:", users[0].name);\nconsole.groupEnd();\n\n// Debugger breakpoint\nfunction calculate(a, b) {\n    debugger; // pauses here in DevTools\n    return a + b;\n}`,
